1	/**
2	 * AI Gateway Routes
3	 *
4	 * HTTP routes for the AI Gateway that routes AI requests from WordPress
5	 * to provider APIs (Anthropic, OpenAI, Google) with tracking and rate limiting.
6	 *
7	 * Endpoints:
8	 *   POST /ai-gateway/v1/chat/completions  — text generation (all providers)
9	 *   POST /ai-gateway/v1/images/generations — image generation (OpenAI)
10	 *   GET  /ai-gateway/v1/models             — list available models
11	 */
12	
13	import * as http from 'http';
14	import type { RegistryStorage } from '../content/IndexRegistry';
15	import { STORAGE_KEYS } from '../../common/constants';
16	import { getSiteIdFromToken } from './token-manager';
17	import { translateToAnthropic, translateFromAnthropic } from './format-translator';
18	import { callAnthropicAPI, calculateAnthropicCost } from './anthropic-client';
19	import { callOpenAIAPI, calculateOpenAICost } from './openai-client';
20	import { callGoogleAPI, calculateGoogleCost, callGoogleImageAPI, calculateGoogleImageCost, GOOGLE_IMAGE_MODELS } from './google-client';
21	import { callImageAPI, calculateImageCost, IMAGE_MODELS, ImageGenerationRequest } from './image-client';
22	import { checkRateLimit } from './rate-limiter';
23	import {
24	  OpenAIChatCompletionRequest,
25	  OpenAIChatCompletionResponse,
26	  GatewayUsageRecord,
27	} from './types';
28	
29	type ChatProvider = 'anthropic' | 'openai' | 'google';
30	
31	/**
32	 * Maps known model IDs to their chat provider.
33	 * Falls back to the globally configured provider for unknown models.
34	 */
35	const MODEL_PROVIDER_MAP: Record<string, ChatProvider> = {
36	  // Anthropic — current models
37	  'claude-opus-4-6':            'anthropic',
38	  'claude-sonnet-4-6':          'anthropic',
39	  'claude-haiku-4-5-20251001':  'anthropic',
40	  'claude-haiku-4-5':           'anthropic',
41	  // Anthropic — legacy (still available)
42	  'claude-sonnet-4-5-20250929': 'anthropic',
43	  'claude-opus-4-5-20251101':   'anthropic',
44	  'claude-sonnet-4-20250514':   'anthropic',
45	  'claude-opus-4-20250514':     'anthropic',
46	
47	  // OpenAI — GPT-4.1 family
48	  'gpt-4.1':          'openai',
49	  'gpt-4.1-mini':     'openai',
50	  'gpt-4.1-nano':     'openai',
51	  // OpenAI — GPT-4o family
52	  'gpt-4o':           'openai',
53	  'gpt-4o-mini':      'openai',
54	  // OpenAI — reasoning models
55	  'o4-mini':          'openai',
56	  'o3':               'openai',
57	  'o3-mini':          'openai',
58	  'o1':               'openai',
59	  'o1-mini':          'openai',
60	
61	  // Google — Gemini 2.x
62	  'gemini-2.5-pro':          'google',
63	  'gemini-2.5-flash':        'google',
64	  'gemini-2.0-flash':        'google',
65	  'gemini-2.0-flash-lite':   'google',
66	  // Google — Gemini 1.5
67	  'gemini-1.5-pro':          'google',
68	  'gemini-1.5-flash':        'google',
69	  'gemini-1.5-flash-8b':     'google',
70	};
71	
72	/** Models surfaced in /models by provider */
73	const CATALOG = {
74	  anthropic: [
75	    { id: 'claude-opus-4-6',           label: 'Claude Opus 4.6',   tier: 'powerful' },
76	    { id: 'claude-sonnet-4-6',         label: 'Claude Sonnet 4.6', tier: 'balanced' },
77	    { id: 'claude-haiku-4-5-20251001', label: 'Claude Haiku 4.5',  tier: 'fast'     },
78	  ],
79	  openai: [
80	    { id: 'gpt-4.1',       label: 'GPT-4.1',       tier: 'powerful' },
81	    { id: 'gpt-4.1-mini',  label: 'GPT-4.1 Mini',  tier: 'balanced' },
82	    { id: 'gpt-4.1-nano',  label: 'GPT-4.1 Nano',  tier: 'fast'     },
83	    { id: 'gpt-4o',        label: 'GPT-4o',         tier: 'powerful' },
84	    { id: 'gpt-4o-mini',   label: 'GPT-4o Mini',    tier: 'balanced' },
85	    { id: 'o4-mini',       label: 'o4-mini',         tier: 'reasoning' },
86	    { id: 'o3',            label: 'o3',               tier: 'reasoning' },
87	    { id: 'o3-mini',       label: 'o3-mini',          tier: 'reasoning' },
88	    { id: 'o1',            label: 'o1',               tier: 'reasoning' },
89	    { id: 'o1-mini',       label: 'o1-mini',          tier: 'reasoning' },
90	  ],
91	  openai_image: [
92	    { id: 'gpt-image-1',      label: 'GPT Image 1',      tier: 'image' },
93	    { id: 'gpt-image-1.5',    label: 'GPT Image 1.5',    tier: 'image' },
94	    { id: 'gpt-image-1-mini', label: 'GPT Image 1 Mini', tier: 'image' },
95	    { id: 'dall-e-3',         label: 'DALL·E 3',          tier: 'image' },
96	    { id: 'dall-e-2',         label: 'DALL·E 2',          tier: 'image' },
97	  ],
98	  google: [
99	    { id: 'gemini-2.5-pro',        label: 'Gemini 2.5 Pro',        tier: 'powerful' },
100	    { id: 'gemini-2.5-flash',      label: 'Gemini 2.5 Flash',      tier: 'balanced' },
101	    { id: 'gemini-2.0-flash',      label: 'Gemini 2.0 Flash',      tier: 'balanced' },
102	    { id: 'gemini-2.0-flash-lite', label: 'Gemini 2.0 Flash Lite', tier: 'fast'     },
103	    { id: 'gemini-1.5-pro',        label: 'Gemini 1.5 Pro',        tier: 'powerful' },
104	    { id: 'gemini-1.5-flash',      label: 'Gemini 1.5 Flash',      tier: 'balanced' },
105	  ],
106	  google_image: [
107	    { id: 'imagen-4.0-generate-001',       label: 'Imagen 4',       tier: 'image' },
108	    { id: 'imagen-4.0-ultra-generate-001', label: 'Imagen 4 Ultra', tier: 'image' },
109	    { id: 'imagen-4.0-fast-generate-001',  label: 'Imagen 4 Fast',  tier: 'image' },
110	  ],
111	};
112	
113	export interface AIGatewayRoutesOptions {
114	  storage: RegistryStorage;
115	  logger: {
116	    info: (msg: string) => void;
117	    error: (msg: string, ...args: any[]) => void;
118	    warn: (msg: string) => void;
119	  };
120	  onUsageRecorded?: (record: GatewayUsageRecord) => void;
121	}
122	
123	export class AIGatewayRoutes {
124	  private storage: RegistryStorage;
125	  private logger: any;
126	  private onUsageRecorded?: (record: GatewayUsageRecord) => void;
127	
128	  constructor(options: AIGatewayRoutesOptions) {
129	    this.storage = options.storage;
130	    this.logger = options.logger;
131	    this.onUsageRecorded = options.onUsageRecorded;
132	  }
133	
134	  /**
135	   * Handle /ai-gateway/v1/chat/completions endpoint
136	   */
137	  async handleChatCompletions(
138	    req: http.IncomingMessage,
139	    res: http.ServerResponse,
140	  ): Promise<void> {
141	    const siteId = this.authenticateRequest(req, res);
142	    if (!siteId) return;
143	
144	    const body = await this.readBody(req);
145	    let openAIRequest: OpenAIChatCompletionRequest;
146	    try {
147	      openAIRequest = JSON.parse(body);
148	    } catch {
149	      this.sendError(res, 400, 'Invalid JSON in request body');
150	      return;
151	    }
152	
153	    if (!openAIRequest.model || !openAIRequest.messages) {
154	      this.sendError(res, 400, 'Missing required fields: model, messages');
155	      return;
156	    }
157	
158	    this.logger.info(
159	      `[AIGateway] Chat request from site ${siteId}: model=${openAIRequest.model}, messages=${openAIRequest.messages.length}`,
160	    );
161	
162	    const rateLimitStatus = checkRateLimit(this.storage, siteId);
163	    if (!rateLimitStatus.allowed) {
164	      this.logger.warn(`[AIGateway] Rate limit exceeded for site ${siteId}: ${rateLimitStatus.reason}`);
165	      this.sendError(res, 429, rateLimitStatus.reason || 'Rate limit exceeded');
166	      return;
167	    }
168	
169	    const apiKeys = (this.storage.get(STORAGE_KEYS.API_KEYS) ?? {}) as Record<string, string>;
170	    const settings = (this.storage.get(STORAGE_KEYS.SETTINGS) ?? {}) as Record<string, any>;
171	    const model = openAIRequest.model;
172	    const globalProvider: ChatProvider = (settings.aiProvider ?? 'anthropic') as ChatProvider;
173	    const resolvedProvider: ChatProvider = (MODEL_PROVIDER_MAP[model] ?? globalProvider) as ChatProvider;
174	
175	    const startTime = Date.now();
176	    let openAIResponse: any;
177	    let promptTokens: number;
178	    let completionTokens: number;
179	    let responseId: string;
180	    let actualProvider: string;
181	    let costUsd: number;
182	
183	    if (resolvedProvider === 'anthropic') {
184	      const anthropicKey = apiKeys.anthropic;
185	      if (!anthropicKey) { this.sendError(res, 503, 'Anthropic API key not configured in Local'); return; }
186	
187	      const anthropicRequest = translateToAnthropic(openAIRequest);
188	      let anthropicResponse;
189	      try {
190	        anthropicResponse = await callAnthropicAPI(anthropicRequest, { apiKey: anthropicKey, logger: this.logger });
191	      } catch (err) {
192	        this.logger.error('[AIGateway] Anthropic API call failed:', err);
193	        this.sendError(res, 502, `Anthropic API error: ${err instanceof Error ? err.message : 'Unknown error'}`);
194	        return;
195	      }
196	
197	      openAIResponse    = translateFromAnthropic(anthropicResponse);
198	      promptTokens      = anthropicResponse.usage.input_tokens;
199	      completionTokens  = anthropicResponse.usage.output_tokens;
200	      responseId        = anthropicResponse.id;
201	      actualProvider    = 'anthropic';
202	      costUsd           = calculateAnthropicCost(model, promptTokens, completionTokens);
203	
204	    } else if (resolvedProvider === 'openai') {
205	      const openaiKey = apiKeys.openai;
206	      if (!openaiKey) { this.sendError(res, 503, 'OpenAI API key not configured in Local'); return; }
207	
208	      let openaiResponse;
209	      try {
210	        openaiResponse = await callOpenAIAPI(openAIRequest, { apiKey: openaiKey, logger: this.logger });
211	      } catch (err) {
212	        this.logger.error('[AIGateway] OpenAI API call failed:', err);
213	        this.sendError(res, 502, `OpenAI API error: ${err instanceof Error ? err.message : 'Unknown error'}`);
214	        return;
215	      }
216	
217	      openAIResponse    = openaiResponse;
218	      promptTokens      = openaiResponse.usage?.prompt_tokens ?? 0;
219	      completionTokens  = openaiResponse.usage?.completion_tokens ?? 0;
220	      responseId        = openaiResponse.id ?? `chatcmpl-${Date.now()}`;
221	      actualProvider    = 'openai';
222	      costUsd           = calculateOpenAICost(model, promptTokens, completionTokens);
223	
224	    } else if (resolvedProvider === 'google') {
225	      const googleKey = apiKeys.google;
226	      if (!googleKey) { this.sendError(res, 503, 'Google API key not configured in Local'); return; }
227	
228	      let googleResponse;
229	      try {
230	        googleResponse = await callGoogleAPI(openAIRequest, { apiKey: googleKey, logger: this.logger });
231	      } catch (err) {
232	        this.logger.error('[AIGateway] Google API call failed:', err);
233	        this.sendError(res, 502, `Google API error: ${err instanceof Error ? err.message : 'Unknown error'}`);
234	        return;
235	      }
236	
237	      openAIResponse    = googleResponse;
238	      promptTokens      = googleResponse.usage?.prompt_tokens ?? 0;
239	      completionTokens  = googleResponse.usage?.completion_tokens ?? 0;
240	      responseId        = googleResponse.id ?? `chatcmpl-google-${Date.now()}`;
241	      actualProvider    = 'google';
242	      costUsd           = calculateGoogleCost(model, promptTokens, completionTokens);
243	
244	    } else {
245	      this.sendError(res, 503, `No API key configured for model: ${model}`);
246	      return;
247	    }
248	
249	    this.recordAndRespond(req, res, siteId, model, actualProvider, openAIResponse,
250	      promptTokens, completionTokens, responseId, costUsd, Date.now() - startTime);
251	  }
252	
253	  /**
254	   * Handle /ai-gateway/v1/images/generations endpoint (OpenAI-compatible).
255	   */
256	  async handleImageGenerations(
257	    req: http.IncomingMessage,
258	    res: http.ServerResponse,
259	  ): Promise<void> {
260	    const siteId = this.authenticateRequest(req, res);
261	    if (!siteId) return;
262	
263	    const body = await this.readBody(req);
264	    let imageRequest: ImageGenerationRequest;
265	    try {
266	      imageRequest = JSON.parse(body);
267	    } catch {
268	      this.sendError(res, 400, 'Invalid JSON in request body');
269	      return;
270	    }
271	
272	    if (!imageRequest.model || !imageRequest.prompt) {
273	      this.sendError(res, 400, 'Missing required fields: model, prompt');
274	      return;
275	    }
276	
277	    const isGoogleImage = GOOGLE_IMAGE_MODELS.has(imageRequest.model);
278	    const isOpenAIImage = IMAGE_MODELS.has(imageRequest.model);
279	
280	    if (!isGoogleImage && !isOpenAIImage) {
281	      const all = [...IMAGE_MODELS, ...GOOGLE_IMAGE_MODELS].join(', ');
282	      this.sendError(res, 400, `Unsupported image model: ${imageRequest.model}. Supported: ${all}`);
283	      return;
284	    }
285	
286	    const apiKeys = (this.storage.get(STORAGE_KEYS.API_KEYS) ?? {}) as Record<string, string>;
287	
288	    this.logger.info(
289	      `[AIGateway] Image request from site ${siteId}: model=${imageRequest.model}, prompt="${imageRequest.prompt.substring(0, 60)}..."`,
290	    );
291	
292	    const startTime = Date.now();
293	    let imageResponse;
294	    let costUsd: number;
295	
296	    if (isGoogleImage) {
297	      const googleKey = apiKeys.google;
298	      if (!googleKey) {
299	        this.sendError(res, 503, 'Google API key not configured in Local (required for Imagen)');
300	        return;
301	      }
302	      try {
303	        imageResponse = await callGoogleImageAPI(imageRequest, { apiKey: googleKey, logger: this.logger });
304	      } catch (err) {
305	        this.logger.error('[AIGateway] Imagen API call failed:', err);
306	        this.sendError(res, 502, `Imagen API error: ${err instanceof Error ? err.message : 'Unknown error'}`);
307	        return;
308	      }
309	      costUsd = calculateGoogleImageCost(imageRequest.model, imageRequest.n ?? 1);
310	    } else {
311	      const openaiKey = apiKeys.openai;
312	      if (!openaiKey) {
313	        this.sendError(res, 503, 'OpenAI API key not configured in Local (required for image generation)');
314	        return;
315	      }
316	      try {
317	        imageResponse = await callImageAPI(imageRequest, { apiKey: openaiKey, logger: this.logger });
318	      } catch (err) {
319	        this.logger.error('[AIGateway] Image API call failed:', err);
320	        this.sendError(res, 502, `Image API error: ${err instanceof Error ? err.message : 'Unknown error'}`);
321	        return;
322	      }
323	      costUsd = calculateImageCost(imageRequest.model, imageRequest.n ?? 1, imageRequest.size ?? '1024x1024');
324	    }
325	
326	    const durationMs = Date.now() - startTime;
327	
328	    this.logger.info(
329	      `[AIGateway] Image success: site=${siteId}, model=${imageRequest.model}, n=${imageRequest.n ?? 1}, cost=$${costUsd.toFixed(4)}, duration=${durationMs}ms`,
330	    );
331	
332	    // Record usage (no token counts for image gen)
333	    const usageRecord: GatewayUsageRecord = {
334	      id: `img-${Date.now()}`,
335	      siteId,
336	      siteName: this.getSiteName(siteId),
337	      model: imageRequest.model,
338	      provider: 'openai',
339	      timestamp: Date.now(),
340	      promptTokens: 0,
341	      completionTokens: 0,
342	      totalTokens: 0,
343	      costUsd,
344	      durationMs,
345	    };
346	    this.storeUsageRecord(usageRecord);
347	    if (this.onUsageRecorded) this.onUsageRecorded(usageRecord);
348	
349	    res.writeHead(200, { 'Content-Type': 'application/json' });
350	    res.end(JSON.stringify(imageResponse));
351	  }
352	
353	  /**
354	   * Handle /ai-gateway/v1/models endpoint.
355	   *
356	   * Returns ONLY models for the globally configured provider — this ensures
357	   * WordPress plugins surface the right model list and don't accidentally pick
358	   * a model from a different provider than what the user configured.
359	   */
360	  handleModels(_req: http.IncomingMessage, res: http.ServerResponse): void {
361	    const apiKeys = (this.storage.get(STORAGE_KEYS.API_KEYS) ?? {}) as Record<string, string>;
362	    const settings = (this.storage.get(STORAGE_KEYS.SETTINGS) ?? {}) as Record<string, any>;
363	    const globalProvider: string = settings.aiProvider || 'anthropic';
364	
365	    const models: Array<{ id: string; object: string; created: number; owned_by: string }> = [];
366	    const ts = 1700000000;
367	
368	    switch (globalProvider) {
369	      case 'openai':
370	        if (apiKeys.openai) {
371	          for (const m of [...CATALOG.openai, ...CATALOG.openai_image]) {
372	            models.push({ id: m.id, object: 'model', created: ts, owned_by: 'openai' });
373	          }
374	        }
375	        break;
376	      case 'google':
377	        if (apiKeys.google) {
378	          for (const m of [...CATALOG.google, ...CATALOG.google_image]) {
379	            models.push({ id: m.id, object: 'model', created: ts, owned_by: 'google' });
380	          }
381	        }
382	        break;
383	      case 'anthropic':
384	      default:
385	        if (apiKeys.anthropic) {
386	          for (const m of CATALOG.anthropic) {
387	            models.push({ id: m.id, object: 'model', created: ts, owned_by: 'anthropic' });
388	          }
389	        }
390	        break;
391	    }
392	
393	    // Fallback: no key for global provider — return that provider's catalog anyway
394	    // so the plugin at least sees what models are expected (user needs to add the key)
395	    if (models.length === 0) {
396	      const fallback = globalProvider === 'openai' ? CATALOG.openai
397	        : globalProvider === 'google' ? CATALOG.google
398	        : CATALOG.anthropic;
399	      for (const m of fallback) {
400	        models.push({ id: m.id, object: 'model', created: ts, owned_by: globalProvider });
401	      }
402	    }
403	
404	    res.writeHead(200, { 'Content-Type': 'application/json' });
405	    res.end(JSON.stringify({ object: 'list', data: models }));
406	  }
407	
408	  // ---------------------------------------------------------------------------
409	  // Private helpers
410	  // ---------------------------------------------------------------------------
411	
412	  /**
413	   * Validate X-Auth-Token and return siteId, or send 401 and return null.
414	   */
415	  private authenticateRequest(req: http.IncomingMessage, res: http.ServerResponse): string | null {
416	    const authToken = req.headers['x-auth-token'] as string | undefined;
417	    if (!authToken) { this.sendError(res, 401, 'Missing X-Auth-Token header'); return null; }
418	
419	    let siteId = getSiteIdFromToken(this.storage, authToken);
420	    if (!siteId) {
421	      const webhookInfo = this.storage.get('http_webhook_info') as { authToken?: string } | null;
422	      const webhookToken = webhookInfo?.authToken;
423	      if (webhookToken && authToken === webhookToken) {
424	        const headerSiteId = req.headers['x-wp-site-id'] as string | undefined;
425	        if (headerSiteId) {
426	          const indexRegistry = this.storage.get(STORAGE_KEYS.INDEX_REGISTRY) as Record<string, unknown> | null;
427	          if (indexRegistry && Object.prototype.hasOwnProperty.call(indexRegistry, headerSiteId)) {
428	            siteId = headerSiteId;
429	          }
430	        }
431	      }
432	    }
433	    if (!siteId) { this.sendError(res, 401, 'Invalid authentication token'); return null; }
434	    return siteId;
435	  }
436	
437	  private recordAndRespond(
438	    req: http.IncomingMessage,
439	    res: http.ServerResponse,
440	    siteId: string,
441	    model: string,
442	    actualProvider: string,
443	    openAIResponse: any,
444	    promptTokens: number,
445	    completionTokens: number,
446	    responseId: string,
447	    costUsd: number,
448	    durationMs: number,
449	  ): void {
450	    const callerPlugin   = req.headers['x-wp-caller-plugin'] as string | undefined;
451	    const callerTheme    = req.headers['x-wp-caller-theme'] as string | undefined;
452	    const callerFeature  = req.headers['x-wp-caller-feature'] as string | undefined;
453	    const callerSource   = req.headers['x-wp-caller-source'] as string | undefined;
454	    const callerUserId   = req.headers['x-wp-user-id'] as string | undefined;
455	    const callerUserRole = req.headers['x-wp-user-role'] as string | undefined;
456	
457	    const usageRecord: GatewayUsageRecord = {
458	      id: responseId,
459	      siteId,
460	      siteName: this.getSiteName(siteId),
461	      model,
462	      provider: actualProvider,
463	      timestamp: Date.now(),
464	      promptTokens,
465	      completionTokens,
466	      totalTokens: promptTokens + completionTokens,
467	      costUsd,
468	      durationMs,
469	      callerPlugin,
470	      callerTheme,
471	      callerFeature,
472	      callerSource,
473	      callerUserId: callerUserId ? parseInt(callerUserId, 10) : undefined,
474	      callerUserRole,
475	    };
476	
477	    const callerDesc = callerPlugin
478	      ? `plugin:${callerPlugin}${callerFeature ? `/${callerFeature}` : ''}`
479	      : callerTheme ? `theme:${callerTheme}`
480	      : callerSource ? `core:${callerFeature || callerSource}`
481	      : 'unknown';
482	
483	    this.logger.info(
484	      `[AIGateway] Success: site=${siteId}, provider=${actualProvider}, caller=${callerDesc}, model=${model}, ` +
485	      `tokens=${usageRecord.totalTokens} (${promptTokens}+${completionTokens}), ` +
486	      `cost=$${costUsd.toFixed(4)}, duration=${durationMs}ms`,
487	    );
488	
489	    this.storeUsageRecord(usageRecord);
490	    if (this.onUsageRecorded) this.onUsageRecorded(usageRecord);
491	
492	    res.writeHead(200, { 'Content-Type': 'application/json' });
493	    res.end(JSON.stringify(openAIResponse));
494	  }
495	
496	  private readBody(req: http.IncomingMessage): Promise<string> {
497	    return new Promise((resolve, reject) => {
498	      let body = '';
499	      req.on('data', (chunk: Buffer) => { body += chunk.toString(); });
500	      req.on('end', () => resolve(body));
501	      req.on('error', (err) => reject(err));
502	    });
503	  }
504	
505	  private sendError(res: http.ServerResponse, statusCode: number, message: string): void {
506	    res.writeHead(statusCode, { 'Content-Type': 'application/json' });
507	    res.end(JSON.stringify({ error: { message, type: 'invalid_request_error' } }));
508	  }
509	
510	  private getSiteName(siteId: string): string {
511	    const indexRegistry = this.storage.get(STORAGE_KEYS.INDEX_REGISTRY) as Record<string, { siteName?: string }> | null;
512	    if (indexRegistry && indexRegistry[siteId]?.siteName) {
513	      return indexRegistry[siteId].siteName!;
514	    }
515	    return siteId;
516	  }
517	
518	  private storeUsageRecord(record: GatewayUsageRecord): void {
519	    const USAGE_KEY = 'nexus_ai_gateway_usage';
520	    const records = (this.storage.get(USAGE_KEY) ?? []) as GatewayUsageRecord[];
521	    records.push(record);
522	    if (records.length > 1000) records.splice(0, records.length - 1000);
