1	/**
2	 * Metrics Collector
3	 *
4	 * Lightweight, in-memory metrics collection for production monitoring.
5	 * Collects counters, gauges, and histograms with minimal overhead.
6	 *
7	 * Integrated with CloudflareTransmitter for anonymous usage analytics.
8	 */
9	
10	import { Counter, Gauge, Histogram, MetricSnapshot, ToolMetrics } from './types';
11	import { CloudflareTransmitter } from './CloudflareTransmitter';
12	
13	export class MetricsCollector {
14	  private static instance: MetricsCollector;
15	
16	  private counters = new Map<string, Counter>();
17	  private gauges = new Map<string, Gauge>();
18	  private histograms = new Map<string, Histogram>();
19	
20	  // Tool-specific metrics tracking
21	  private toolCalls = new Map<string, number[]>(); // tool name => [duration1, duration2, ...]
22	  private toolErrors = new Map<string, number>(); // tool name => error count
23	
24	  private startTime = Date.now();
25	
26	  private constructor() {
27	    // Private constructor for singleton
28	  }
29	
30	  static getInstance(): MetricsCollector {
31	    if (!MetricsCollector.instance) {
32	      MetricsCollector.instance = new MetricsCollector();
33	    }
34	    return MetricsCollector.instance;
35	  }
36	
37	  /**
38	   * Increment a counter
39	   */
40	  increment(name: string, labels?: Record<string, string>, value: number = 1): void {
41	    const key = this.makeKey(name, labels);
42	    const existing = this.counters.get(key);
43	    if (existing) {
44	      existing.value += value;
45	    } else {
46	      this.counters.set(key, { name, value, labels });
47	    }
48	  }
49	
50	  /**
51	   * Set a gauge value
52	   */
53	  setGauge(name: string, value: number, labels?: Record<string, string>): void {
54	    const key = this.makeKey(name, labels);
55	    this.gauges.set(key, { name, value, labels });
56	  }
57	
58	  /**
59	   * Record a histogram value
60	   */
61	  recordHistogram(name: string, value: number, labels?: Record<string, string>): void {
62	    const key = this.makeKey(name, labels);
63	    const existing = this.histograms.get(key);
64	    if (existing) {
65	      existing.values.push(value);
66	    } else {
67	      this.histograms.set(key, { name, values: [value], labels });
68	    }
69	  }
70	
71	  /**
72	   * Record a tool call (duration in ms)
73	   */
74	  recordToolCall(
75	    toolName: string,
76	    duration_ms: number,
77	    isError: boolean = false,
78	    accessMethod?: 'mcp' | 'cli',
79	  ): void {
80	    // Track duration
81	    const durations = this.toolCalls.get(toolName) || [];
82	    durations.push(duration_ms);
83	    this.toolCalls.set(toolName, durations);
84	
85	    // Track errors
86	    if (isError) {
87	      const errorCount = this.toolErrors.get(toolName) || 0;
88	      this.toolErrors.set(toolName, errorCount + 1);
89	    }
90	
91	    // Update metrics
92	    this.increment('mcp_tool_calls_total', { tool: toolName });
93	    this.recordHistogram('mcp_tool_duration_ms', duration_ms, { tool: toolName });
94	
95	    if (isError) {
96	      this.increment('mcp_tool_errors_total', { tool: toolName });
97	    }
98	
99	    // Transmit to Cloudflare for anonymous analytics (fire-and-forget)
100	    CloudflareTransmitter.recordToolCall(toolName, duration_ms, !isError, accessMethod);
101	  }
102	
103	  /**
104	   * Get tool metrics for a specific tool
105	   */
106	  getToolMetrics(toolName: string): ToolMetrics | null {
107	    const durations = this.toolCalls.get(toolName);
108	    if (!durations || durations.length === 0) {
109	      return null;
110	    }
111	
112	    const sorted = durations.slice().sort((a, b) => a - b);
113	    const total = durations.reduce((sum, d) => sum + d, 0);
114	    const errors = this.toolErrors.get(toolName) || 0;
115	
116	    return {
117	      name: toolName,
118	      calls: durations.length,
119	      errors,
120	      total_duration_ms: total,
121	      avg_duration_ms: total / durations.length,
122	      min_duration_ms: sorted[0],
123	      max_duration_ms: sorted[sorted.length - 1],
124	      p50_duration_ms: sorted[Math.floor(sorted.length * 0.5)],
125	      p95_duration_ms: sorted[Math.floor(sorted.length * 0.95)],
126	      p99_duration_ms: sorted[Math.floor(sorted.length * 0.99)],
127	    };
128	  }
129	
130	  /**
131	   * Get all tool metrics
132	   */
133	  getAllToolMetrics(): ToolMetrics[] {
134	    const metrics: ToolMetrics[] = [];
135	    for (const toolName of this.toolCalls.keys()) {
136	      const toolMetric = this.getToolMetrics(toolName);
137	      if (toolMetric) {
138	        metrics.push(toolMetric);
139	      }
140	    }
141	    return metrics.sort((a, b) => b.calls - a.calls);
142	  }
143	
144	  /**
145	   * Get uptime in milliseconds
146	   */
147	  getUptime(): number {
148	    return Date.now() - this.startTime;
149	  }
150	
151	  /**
152	   * Get current snapshot of all metrics
153	   */
154	  getSnapshot(): MetricSnapshot {
155	    return {
156	      timestamp: new Date().toISOString(),
157	      counters: new Map(this.counters),
158	      gauges: new Map(this.gauges),
159	      histograms: new Map(this.histograms),
160	    };
161	  }
162	
163	  /**
164	   * Reset all metrics
165	   */
166	  reset(): void {
167	    this.counters.clear();
168	    this.gauges.clear();
169	    this.histograms.clear();
170	    this.toolCalls.clear();
171	    this.toolErrors.clear();
172	    this.startTime = Date.now();
173	  }
174	
175	  /**
176	   * Export metrics to JSON
177	   */
178	  toJSON(): any {
179	    const snapshot = this.getSnapshot();
180	    return {
181	      timestamp: snapshot.timestamp,
182	      uptime_ms: this.getUptime(),
183	      counters: Array.from(snapshot.counters.values()),
184	      gauges: Array.from(snapshot.gauges.values()),
185	      histograms: Array.from(snapshot.histograms.entries()).map(([key, hist]) => ({
186	        name: hist.name,
187	        labels: hist.labels,
188	        count: hist.values.length,
189	        sum: hist.values.reduce((a, b) => a + b, 0),
190	        min: Math.min(...hist.values),
191	        max: Math.max(...hist.values),
192	        avg: hist.values.reduce((a, b) => a + b, 0) / hist.values.length,
193	      })),
194	      tools: this.getAllToolMetrics(),
195	    };
196	  }
197	
198	  private makeKey(name: string, labels?: Record<string, string>): string {
199	    if (!labels) {
200	      return name;
201	    }
202	    const labelStr = Object.entries(labels)
203	      .sort(([a], [b]) => a.localeCompare(b))
204	      .map(([k, v]) => `${k}="${v}"`)
205	      .join(',');
206	    return `${name}{${labelStr}}`;
207	  }
208	}
209	
210	/**
211	 * Get the singleton metrics collector
212	 */
213	export function getMetrics(): MetricsCollector {
214	  return MetricsCollector.getInstance();
215	}
