1	/**
2	 * Telemetry Configuration Management
3	 *
4	 * Manages installation ID, secret key, and telemetry opt-in status.
5	 * Pattern based on lwp CLI analytics configuration.
6	 *
7	 * Privacy:
8	 * - installationId: Random UUID (not tied to user identity)
9	 * - secretKey: Random 32 bytes for HMAC signing (never transmitted after registration)
10	 * - All config files stored with 0600 permissions (user read/write only)
11	 */
12	
13	import * as fs from 'fs';
14	import * as path from 'path';
15	import * as os from 'os';
16	import * as crypto from 'crypto';
17	
18	// ============================================================================
19	// Types
20	// ============================================================================
21	
22	export interface TelemetryConfig {
23	  installationId: string;     // Random UUID identifies this installation
24	  secretKey: string;          // Random 32 bytes (base64) for HMAC signing
25	  registeredAt?: string;      // When first synced to Cloudflare server
26	  telemetry: {
27	    enabled: boolean;         // Default: true (opt-out model)
28	    promptedAt: string | null;
29	  };
30	}
31	
32	// ============================================================================
33	// Constants
34	// ============================================================================
35	
36	const CONFIG_DIR = path.join(os.homedir(), 'Library', 'Application Support', 'Local', 'nexus-ai');
37	const CONFIG_PATH = path.join(CONFIG_DIR, 'config.json');
38	const EVENTS_DIR = path.join(CONFIG_DIR, 'telemetry');
39	const EVENTS_PATH = path.join(EVENTS_DIR, 'events.jsonl');
40	
41	// Environment variable overrides
42	const ENV_TELEMETRY = process.env.NEXUS_TELEMETRY; // '0' or '1'
43	const ENV_ENDPOINT = process.env.NEXUS_ANALYTICS_ENDPOINT;
44	
45	// CI environments where telemetry is auto-disabled
46	const CI_ENV_VARS = [
47	  'CI',
48	  'GITHUB_ACTIONS',
49	  'GITLAB_CI',
50	  'JENKINS_URL',
51	  'TRAVIS',
52	  'CIRCLECI',
53	  'BUILDKITE',
54	];
55	
56	// ============================================================================
57	// Path Accessors (for testability)
58	// ============================================================================
59	
60	export function getConfigDir(): string {
61	  return CONFIG_DIR;
62	}
63	
64	export function getConfigPath(): string {
65	  return CONFIG_PATH;
66	}
67	
68	export function getEventsDir(): string {
69	  return EVENTS_DIR;
70	}
71	
72	export function getEventsPath(): string {
73	  return EVENTS_PATH;
74	}
75	
76	export function getAnalyticsEndpoint(): string {
77	  const base = ENV_ENDPOINT || 'https://analytics.elasticapi.io';
78	  return base.replace(/\/$/, '') + '/v1/events';
79	}
80	
81	// ============================================================================
82	// Directory Management
83	// ============================================================================
84	
85	function ensureDir(dirPath: string): void {
86	  if (!fs.existsSync(dirPath)) {
87	    fs.mkdirSync(dirPath, { recursive: true, mode: 0o700 });
88	  }
89	}
90	
91	// ============================================================================
92	// ID and Key Generation
93	// ============================================================================
94	
95	export function generateInstallationId(): string {
96	  return crypto.randomUUID();
97	}
98	
99	export function generateSecretKey(): string {
100	  return crypto.randomBytes(32).toString('base64');
101	}
102	
103	// ============================================================================
104	// Config Read/Write
105	// ============================================================================
106	
107	export function readConfig(): TelemetryConfig {
108	  try {
109	    if (fs.existsSync(CONFIG_PATH)) {
110	      const data = fs.readFileSync(CONFIG_PATH, 'utf-8');
111	      const config = JSON.parse(data);
112	
113	      // Validate structure
114	      if (typeof config.telemetry?.enabled === 'boolean') {
115	        let needsWrite = false;
116	
117	        // Ensure installationId exists (migrate from old configs)
118	        if (!config.installationId) {
119	          config.installationId = generateInstallationId();
120	          needsWrite = true;
121	        }
122	
123	        // Ensure secretKey exists
124	        if (!config.secretKey) {
125	          config.secretKey = generateSecretKey();
126	          needsWrite = true;
127	        }
128	
129	        if (needsWrite) {
130	          writeConfig(config);
131	        }
132	
133	        return config;
134	      }
135	    }
136	  } catch {
137	    // Corrupted config, will regenerate
138	  }
139	
140	  // Default: enabled (opt-out model) with new credentials
141	  // Write to disk immediately so the same IDs are used on every subsequent call
142	  const fresh: TelemetryConfig = {
143	    installationId: generateInstallationId(),
144	    secretKey: generateSecretKey(),
145	    telemetry: { enabled: true, promptedAt: null },
146	  };
147	  try {
148	    writeConfig(fresh);
149	  } catch {
150	    // Best-effort — if we can't write, IDs will be inconsistent but telemetry still works
151	  }
152	  return fresh;
153	}
154	
155	export function writeConfig(config: TelemetryConfig): void {
156	  ensureDir(CONFIG_DIR);
157	
158	  // Atomic write: temp file + rename
159	  const tempPath = `${CONFIG_PATH}.${process.pid}.tmp`;
160	  fs.writeFileSync(tempPath, JSON.stringify(config, null, 2), 'utf-8');
161	  fs.chmodSync(tempPath, 0o600); // User read/write only
162	  fs.renameSync(tempPath, CONFIG_PATH);
163	}
164	
165	// ============================================================================
166	// Config Accessors
167	// ============================================================================
168	
169	export function getInstallationId(): string {
170	  return readConfig().installationId;
171	}
172	
173	export function getSecretKey(): string {
174	  return readConfig().secretKey;
175	}
176	
177	export function markAsRegistered(): void {
178	  const config = readConfig();
179	  config.registeredAt = new Date().toISOString();
180	  writeConfig(config);
181	}
182	
183	export function isRegistered(): boolean {
184	  return !!readConfig().registeredAt;
185	}
186	
187	// ============================================================================
188	// Telemetry Enabled/Disabled
189	// ============================================================================
190	
191	export function isTelemetryEnabled(): boolean {
192	  // Environment variable override
193	  if (ENV_TELEMETRY === '0') return false;
194	  if (ENV_TELEMETRY === '1') return true;
195	
196	  // Auto-disable in CI environments
197	  if (CI_ENV_VARS.some((v) => process.env[v])) return false;
198	
199	  // Use config value
200	  return readConfig().telemetry.enabled;
201	}
202	
203	export function setTelemetryEnabled(enabled: boolean): void {
204	  const config = readConfig();
205	  config.telemetry.enabled = enabled;
206	  config.telemetry.promptedAt = config.telemetry.promptedAt || new Date().toISOString();
207	  writeConfig(config);
208	}
209	
210	export function hasBeenPrompted(): boolean {
211	  return readConfig().telemetry.promptedAt !== null;
212	}
213	
214	// ============================================================================
215	// Events File Management
216	// ============================================================================
217	
218	export const MAX_EVENTS = 10000;
219	
220	export function ensureEventsDir(): void {
221	  ensureDir(EVENTS_DIR);
222	}
223	
224	export function rotateEventsIfNeeded(): void {
225	  const eventsPath = getEventsPath();
226	  if (!fs.existsSync(eventsPath)) return;
227	
228	  const content = fs.readFileSync(eventsPath, 'utf-8');
229	  const lines = content.trim().split('\n').filter(Boolean);
230	
231	  if (lines.length >= MAX_EVENTS) {
232	    // Keep newest 80%
233	    const keepCount = Math.floor(MAX_EVENTS * 0.8);
234	    const toKeep = lines.slice(-keepCount);
235	    fs.writeFileSync(eventsPath, toKeep.join('\n') + '\n', 'utf-8');
236	    fs.chmodSync(eventsPath, 0o600);
237	  }
238	}
239	
240	export function appendEvent(event: any): void {
241	  ensureEventsDir();
242	  rotateEventsIfNeeded();
243	
244	  const line = JSON.stringify(event) + '\n';
245	  fs.appendFileSync(getEventsPath(), line, 'utf-8');
246	  fs.chmodSync(getEventsPath(), 0o600);
247	}
248	
249	export function readEvents(): any[] {
250	  try {
251	    const eventsPath = getEventsPath();
252	    if (!fs.existsSync(eventsPath)) return [];
253	
254	    const content = fs.readFileSync(eventsPath, 'utf-8');
255	    return content
256	      .trim()
257	      .split('\n')
258	      .filter(Boolean)
259	      .map((line) => JSON.parse(line));
260	  } catch {
261	    return [];
262	  }
263	}
264	
265	export function clearEvents(): void {
266	  try {
267	    const eventsPath = getEventsPath();
268	    if (fs.existsSync(eventsPath)) {
269	      fs.unlinkSync(eventsPath);
270	    }
271	  } catch {
272	    // Ignore cleanup errors
273	  }
274	}
275	
276	// ============================================================================
277	// Reset Analytics
278	// ============================================================================
279	
280	export function resetAnalytics(): void {
281	  clearEvents();
282	  const config = readConfig();
283	  config.installationId = generateInstallationId();
284	  config.secretKey = generateSecretKey();
285	  delete config.registeredAt; // Will need to re-register
286	  config.telemetry.enabled = false;
287	  writeConfig(config);
288	}
