1	/**
2	 * Rate limiter for AI Gateway
3	 */
4	
5	import type { RegistryStorage } from '../content/IndexRegistry';
6	import type { RateLimitConfig, RateLimitStatus } from './types';
7	
8	const STORAGE_KEY = 'nexus_ai_rate_limits';
9	const DEFAULT_REQUESTS_PER_HOUR = 100;
10	const DEFAULT_REQUESTS_PER_DAY = 500;
11	const DEFAULT_COST_PER_DAY_USD = 10.0;
12	
13	/**
14	 * Get rate limit configuration for a site
15	 */
16	export function getRateLimit(
17	  storage: RegistryStorage,
18	  siteId: string,
19	): RateLimitConfig {
20	  const limits = (storage.get(STORAGE_KEY) ?? {}) as Record<string, RateLimitConfig>;
21	  return limits[siteId] ?? {
22	    requestsPerHour: DEFAULT_REQUESTS_PER_HOUR,
23	    requestsPerDay: DEFAULT_REQUESTS_PER_DAY,
24	    costPerDayUsd: DEFAULT_COST_PER_DAY_USD,
25	  };
26	}
27	
28	/**
29	 * Set rate limit configuration for a site
30	 */
31	export function setRateLimit(
32	  storage: RegistryStorage,
33	  siteId: string,
34	  config: RateLimitConfig,
35	): void {
36	  const limits = (storage.get(STORAGE_KEY) ?? {}) as Record<string, RateLimitConfig>;
37	  limits[siteId] = config;
38	  storage.set(STORAGE_KEY, limits);
39	}
40	
41	/**
42	 * Check if a request is within rate limits
43	 */
44	export function checkRateLimit(
45	  storage: RegistryStorage,
46	  siteId: string,
47	): RateLimitStatus {
48	  const config = getRateLimit(storage, siteId);
49	
50	  // Get usage records
51	  const USAGE_KEY = 'nexus_ai_gateway_usage';
52	  const allRecords = (storage.get(USAGE_KEY) ?? []) as any[];
53	
54	  // Filter to this site's records
55	  const siteRecords = allRecords.filter((r) => r.siteId === siteId);
56	
57	  const now = Date.now();
58	  const oneHourAgo = now - 60 * 60 * 1000;
59	  const oneDayAgo = now - 24 * 60 * 60 * 1000;
60	
61	  // Count requests in rolling windows
62	  const requestsThisHour = siteRecords.filter((r) => r.timestamp >= oneHourAgo).length;
63	  const requestsThisDay = siteRecords.filter((r) => r.timestamp >= oneDayAgo).length;
64	
65	  // Calculate cost in rolling day
66	  const costThisDayUsd = siteRecords
67	    .filter((r) => r.timestamp >= oneDayAgo)
68	    .reduce((sum, r) => sum + (r.costUsd || 0), 0);
69	
70	  // Check limits
71	  let allowed = true;
72	  let reason: string | undefined;
73	
74	  if (config.requestsPerHour && requestsThisHour >= config.requestsPerHour) {
75	    allowed = false;
76	    reason = `Rate limit exceeded: ${requestsThisHour} requests in the last hour (limit: ${config.requestsPerHour})`;
77	  } else if (config.requestsPerDay && requestsThisDay >= config.requestsPerDay) {
78	    allowed = false;
79	    reason = `Rate limit exceeded: ${requestsThisDay} requests in the last day (limit: ${config.requestsPerDay})`;
80	  } else if (
81	    config.costPerDayUsd &&
82	    costThisDayUsd >= config.costPerDayUsd
83	  ) {
84	    allowed = false;
85	    reason = `Cost limit exceeded: $${costThisDayUsd.toFixed(4)} in the last day (limit: $${config.costPerDayUsd})`;
86	  }
87	
88	  return {
89	    allowed,
90	    reason,
91	    requestsThisHour,
92	    requestsThisDay,
93	    costThisDayUsd,
94	    limits: config,
95	  };
96	}
