437	  private recordAndRespond(
438	    req: http.IncomingMessage,
439	    res: http.ServerResponse,
440	    siteId: string,
441	    model: string,
442	    actualProvider: string,
443	    openAIResponse: any,
444	    promptTokens: number,
445	    completionTokens: number,
446	    responseId: string,
447	    costUsd: number,
448	    durationMs: number,
449	  ): void {
450	    const callerPlugin   = req.headers['x-wp-caller-plugin'] as string | undefined;
451	    const callerTheme    = req.headers['x-wp-caller-theme'] as string | undefined;
452	    const callerFeature  = req.headers['x-wp-caller-feature'] as string | undefined;
453	    const callerSource   = req.headers['x-wp-caller-source'] as string | undefined;
454	    const callerUserId   = req.headers['x-wp-user-id'] as string | undefined;
455	    const callerUserRole = req.headers['x-wp-user-role'] as string | undefined;
456	
457	    const usageRecord: GatewayUsageRecord = {
458	      id: responseId,
459	      siteId,
460	      siteName: this.getSiteName(siteId),
461	      model,
462	      provider: actualProvider,
463	      timestamp: Date.now(),
464	      promptTokens,
465	      completionTokens,
466	      totalTokens: promptTokens + completionTokens,
467	      costUsd,
468	      durationMs,
469	      callerPlugin,
470	      callerTheme,
471	      callerFeature,
472	      callerSource,
473	      callerUserId: callerUserId ? parseInt(callerUserId, 10) : undefined,
474	      callerUserRole,
475	    };
476	
477	    const callerDesc = callerPlugin
478	      ? `plugin:${callerPlugin}${callerFeature ? `/${callerFeature}` : ''}`
479	      : callerTheme ? `theme:${callerTheme}`
480	      : callerSource ? `core:${callerFeature || callerSource}`
481	      : 'unknown';
482	
483	    this.logger.info(
484	      `[AIGateway] Success: site=${siteId}, provider=${actualProvider}, caller=${callerDesc}, model=${model}, ` +
485	      `tokens=${usageRecord.totalTokens} (${promptTokens}+${completionTokens}), ` +
486	      `cost=$${costUsd.toFixed(4)}, duration=${durationMs}ms`,
487	    );
488	
489	    this.storeUsageRecord(usageRecord);
490	    if (this.onUsageRecorded) this.onUsageRecorded(usageRecord);
491	
492	    res.writeHead(200, { 'Content-Type': 'application/json' });
493	    res.end(JSON.stringify(openAIResponse));
494	  }
495	
496	  private readBody(req: http.IncomingMessage): Promise<string> {
497	    return new Promise((resolve, reject) => {
498	      let body = '';
499	      req.on('data', (chunk: Buffer) => { body += chunk.toString(); });
500	      req.on('end', () => resolve(body));
501	      req.on('error', (err) => reject(err));
502	    });
503	  }
504	
505	  private sendError(res: http.ServerResponse, statusCode: number, message: string): void {
506	    res.writeHead(statusCode, { 'Content-Type': 'application/json' });
507	    res.end(JSON.stringify({ error: { message, type: 'invalid_request_error' } }));
508	  }
509	
510	  private getSiteName(siteId: string): string {
511	    const indexRegistry = this.storage.get(STORAGE_KEYS.INDEX_REGISTRY) as Record<string, { siteName?: string }> | null;
512	    if (indexRegistry && indexRegistry[siteId]?.siteName) {
513	      return indexRegistry[siteId].siteName!;
514	    }
515	    return siteId;
516	  }
517	
518	  private storeUsageRecord(record: GatewayUsageRecord): void {
519	    const USAGE_KEY = 'nexus_ai_gateway_usage';
520	    const records = (this.storage.get(USAGE_KEY) ?? []) as GatewayUsageRecord[];
521	    records.push(record);
522	    if (records.length > 1000) records.splice(0, records.length - 1000);
523	    this.storage.set(USAGE_KEY, records);
524	  }
525	}
